import { mkdirSync, readdirSync, readFileSync, rmSync, writeFileSync } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { FUNCTION_ROUTES } from "../src/server/function-routes.js";

const ROOT_DIR = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const GENERATED_HEADER = [
  "/* eslint-disable */",
  "// This file is auto-generated by scripts/generate-function-wrappers.mjs.",
  "// Do not edit it by hand.",
  "",
].join("\n");
const GENERATED_SENTINEL = "This file is auto-generated by scripts/generate-function-wrappers.mjs.";
const MANAGED_OUTPUT_DIRECTORIES = [
  path.join(ROOT_DIR, "api"),
  path.join(ROOT_DIR, "functions", "api"),
  path.join(ROOT_DIR, "cloud-functions", "api"),
];

function renderSharedImports(route, methods, importPath, options = {}) {
  const aliases = methods.map((method) => {
    if (method === "OPTIONS") {
      return `${method} as SHARED_OPTIONS`;
    }

    return method;
  });

  return `${GENERATED_HEADER}import { ${options.dispatchImport} } from "${options.dispatchPath}";
import { ${aliases.join(", ")} } from "${importPath}";

const handlers = {
${methods.map((method) => `  ${method}: ${method === "OPTIONS" ? "SHARED_OPTIONS" : method},`).join("\n")}
};
`;
}

function renderVercelWrapper({ handlerModule, methods }) {
  const handlerImports = methods.map((method) => {
    if (method === "OPTIONS") {
      return `${method} as handleOptions`;
    }

    return `${method} as handle${method[0]}${method.slice(1).toLowerCase()}`;
  });

  const handlerEntries = methods.map((method) => {
    if (method === "OPTIONS") {
      return "  OPTIONS: handleOptions,";
    }

    return `  ${method}: handle${method[0]}${method.slice(1).toLowerCase()},`;
  });

  return `${GENERATED_HEADER}import { handleVercelNodeRequest } from "../src/server/vercel-node.js";
import { ${handlerImports.join(", ")} } from "../${handlerModule}.js";

const handlers = {
${handlerEntries.join("\n")}
};

export default function handler(req: unknown, res: unknown) {
  return handleVercelNodeRequest(
    req as Parameters<typeof handleVercelNodeRequest>[0],
    res as Parameters<typeof handleVercelNodeRequest>[1],
    handlers,
  );
}
`;
}

function renderEdgeRuntimeWrapper(target, { handlerModule, methods }) {
  const base = renderSharedImports(
    handlerModule,
    methods,
    `../../${handlerModule}.js`,
    {
      dispatchImport: "dispatchFunctionRequest",
      dispatchPath: "../../src/server/function-dispatch.js",
    },
  );

  const runtimeFunctions = [
    `export function onRequestGet(context: { request: Request }) {
  return dispatchFunctionRequest("${target}", context.request, handlers);
}`,
    `export function onRequestOptions(context: { request: Request }) {
  return dispatchFunctionRequest("${target}", context.request, handlers);
}`,
  ];

  return `${base}
${runtimeFunctions.join("\n\n")}
`;
}

function writeGeneratedFile(relativePath, content) {
  const fullPath = path.join(ROOT_DIR, relativePath);
  mkdirSync(path.dirname(fullPath), { recursive: true });
  writeFileSync(fullPath, content, "utf8");
}

function removeGeneratedWrappers(directoryPath) {
  for (const entry of readdirSync(directoryPath, { withFileTypes: true })) {
    if (!entry.isFile() || path.extname(entry.name) !== ".ts") {
      continue;
    }

    const filePath = path.join(directoryPath, entry.name);
    const source = readFileSync(filePath, "utf8");
    if (source.includes(GENERATED_SENTINEL)) {
      rmSync(filePath, { force: true });
    }
  }
}

for (const directoryPath of MANAGED_OUTPUT_DIRECTORIES) {
  mkdirSync(directoryPath, { recursive: true });
  removeGeneratedWrappers(directoryPath);
}

for (const routeConfig of FUNCTION_ROUTES) {
  writeGeneratedFile(
    path.join("api", `${routeConfig.route}.ts`),
    renderVercelWrapper(routeConfig),
  );
  writeGeneratedFile(
    path.join("functions", "api", `${routeConfig.route}.ts`),
    renderEdgeRuntimeWrapper("cloudflare", routeConfig),
  );
  writeGeneratedFile(
    path.join("cloud-functions", "api", `${routeConfig.route}.ts`),
    renderEdgeRuntimeWrapper("edgeone", routeConfig),
  );
}
